#include<cstdio>
#include<iostream>
#include<algorithm>
using namespace std;

int dp[155], tit[15], hwt[15], hwpts[15];

int main(){
	int n, m, k, r;
	cin >> n >> m >> k >> r;
	for(int i = 1; i <= n; i++)
	    cin >> tit[i];
	for(int i = 1; i <= m; i++)
	    cin >> hwt[i];
	for(int i = 1; i <= m; i++)
	    cin >> hwpts[i];
	for(int i = 1; i <= r; i++)
	    dp[i] = 0;
	for(int i = 1; i <= m; i++)
	    for(int j = r; j >= hwt[i]; j--)
	        dp[j] = max(dp[j - hwt[i]] + hwpts[i], dp[j]);
	int tme, cnt = 0;
	for(int i = 1; i <= r; i++)
		if(dp[i] >= k) 
		{
			tme = r - i;
			break;
		}
	sort(tit + 1, tit + n + 1);
	for(int i = 1; i <= n; i++)
	{
		tme -= tit[i];
		if(tme <= 0) break;
		cnt++;
	}
	cout << cnt;
	return 0;
}
